import React, { useState } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  // THE ONLY BRAND COLOR: LUXURY GOLD
  const gold = '#D4AF37';

  // State to swap between your categories
  const [activeCategory, setActiveCategory] = useState('Small Chops');

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif' }}>
      
      {/* 1. THE GOLDEN NAVIGATION */}
      <nav style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        padding: '40px 20px', 
        backgroundColor: '#000', 
        borderBottom: '1px solid #111'
      }}>
        {/* LOGO - MAXIMUM VISIBILITY */}
        <img src={Logo} alt="Àmí by T" style={{ 
          height: '130px', 
          width: 'auto',
          marginBottom: '30px',
          filter: 'contrast(130%) brightness(120%)',
          mixBlendMode: 'screen'
        }} />

        {/* THE TABS (PURE GOLD & BLACK) */}
        <div style={{ display: 'flex', gap: '40px' }}>
          {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
            <button 
              key={item} 
              onClick={() => setActiveCategory(item)}
              style={{ 
                background: 'none',
                border: 'none',
                color: gold, 
                fontSize: '0.85rem', 
                fontWeight: '600',
                letterSpacing: '2px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                paddingBottom: '8px',
                borderBottom: activeCategory === item ? `2px solid ${gold}` : '2px solid transparent',
                opacity: activeCategory === item ? 1 : 0.4, // Dim the ones not selected
                transition: '0.3s'
              }}
            >
              {item}
            </button>
          ))}
        </div>
      </nav>

      {/* 2. THE DYNAMIC STAGE */}
      <main style={{ padding: '40px 20px', maxWidth: '1200px', margin: '0 auto' }}>
        
        {/* SMALL CHOPS SECTION */}
        {activeCategory === 'Small Chops' && (
          <div>
            <h2 style={{ 
              color: gold, 
              textAlign: 'center', 
              fontSize: '2rem', 
              marginBottom: '40px',
              fontWeight: '300',
              letterSpacing: '4px',
              textTransform: 'uppercase'
            }}>
              The Small Chops Curates
            </h2>
            <Menu />
          </div>
        )}

        {/* OFFICE LUNCH SECTION */}
        {activeCategory === 'Office Lunch' && (
          <div>
            <h2 style={{ 
              color: gold, 
              textAlign: 'center', 
              fontSize: '2rem', 
              marginBottom: '40px',
              fontWeight: '300',
              letterSpacing: '4px'
            }}>
              Office Lunch Rituals
            </h2>
            <Lunch />
          </div>
        )}

        {/* WIGS SECTION */}
        {activeCategory === 'Wigs' && (
          <div style={{ textAlign: 'center', padding: '100px 20px' }}>
            <h2 style={{ color: gold, fontSize: '2rem', letterSpacing: '4px' }}>Affordable Wigs</h2>
            <p style={{ color: gold, opacity: 0.5, marginTop: '20px' }}>The Hair Edit — Coming Soon</p>
          </div>
        )}

        {/* ABOUT SECTION */}
        {activeCategory === 'About Us' && (
          <div style={{ textAlign: 'center', padding: '80px 20px', color: gold }}>
            <h2 style={{ fontSize: '2rem', letterSpacing: '4px' }}>Àmí by T</h2>
            <p style={{ maxWidth: '600px', margin: '30px auto', lineHeight: '1.8', opacity: 0.8 }}>
              Crafting moments of taste and style in the heart of Lagos. From signature platters to everyday luxury lunch.
            </p>
          </div>
        )}
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '80px 40px', color: '#222', fontSize: '0.7rem' }}>
        <p style={{ letterSpacing: '5px', color: gold, opacity: 0.3 }}>ÀMÍ BY T | LAGOS</p>
      </footer>

    </div>
  );
}

export default App;
